import{_ as a,c as e,o as t,b as m}from"./app.b5c11ed0.js";const k='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 2","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 2","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 2.","tags":"vim-2","date":"2021-02-09T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/2/2/index.md"}',o={},r=m('<div class="stanza"><a href="#s2.2" id="s2.2" class="num">2.2</a><div class="sans"><p>\u0905\u0938\u094D\u092F \u091A\u2014</p><blockquote><p><strong>\u092A\u094D\u0930\u092F\u0924\u094D\u0928\u0903 \u0938\u093E\u0927\u0915\u0903\u0965\u0968\u0965</strong></p></blockquote><p>\u092F\u0925\u094B\u0915\u094D\u0924\u0930\u0942\u092A\u0938\u094D\u092F \u092E\u0928\u094D\u0924\u094D\u0930\u0938\u094D\u092F\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u093F\u0924\u094D\u0938\u093E\u092A\u094D\u0930\u0925\u092E\u094B\u0928\u094D\u092E\u0947\u0937\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092A\u094D\u0930\u092F\u0924\u0928\u093E\u0924\u094D\u092E\u093E \u0905\u0915\u0943\u0924\u0915\u094B \u092F\u0903 \u092A\u094D\u0930\u092F\u0924\u094D\u0928\u0903 \u0938 \u090F\u0935 \u0938\u093E\u0927\u0915\u094B \u092E\u0928\u094D\u0924\u094D\u0930\u092F\u093F\u0924\u0941\u0930\u094D\u092E\u0928\u094D\u0924\u094D\u0930\u0926\u0947\u0935\u0924\u093E\u0924\u093E\u0926\u093E\u0924\u094D\u092E\u094D\u092F\u092A\u094D\u0930\u0926\u0903\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0924\u0928\u094D\u0924\u094D\u0930\u0938\u0926\u094D\u092D\u093E\u0935\u0947</p><blockquote><p>\u0906\u092E\u093F\u0937\u0902 \u0924\u0941 \u092F\u0925\u093E \u0916\u0938\u094D\u0925\u0903 \u0938\u092E\u094D\u092A\u0936\u094D\u092F\u091E\u094D\u0936\u0915\u0941\u0928\u093F\u0903 \u092A\u094D\u0930\u093F\u092F\u0947\u0964<br> \u0915\u094D\u0937\u093F\u092A\u094D\u0930\u092E\u093E\u0915\u0930\u094D\u0937\u092F\u0947\u0926\u094D\u092F\u0926\u094D\u0935\u0926\u094D\u0935\u0947\u0917\u0947\u0928 \u0938\u0939\u091C\u0947\u0928 \u0924\u0941\u0965<br> \u0924\u0926\u094D\u0935\u0926\u0947\u0935 \u0939\u093F \u092F\u094B\u0917\u0940\u0928\u094D\u0926\u094D\u0930\u094B \u092E\u0928\u094B \u092C\u093F\u0928\u094D\u0926\u0941\u0902 \u0935\u093F\u0915\u0930\u094D\u0937\u092F\u0947\u0924\u094D\u0964<br> \u092F\u0925\u093E \u0936\u0930\u094B \u0927\u0928\u0941\u0903\u0938\u0902\u0938\u094D\u0925\u094B \u092F\u0924\u094D\u0928\u0947\u0928\u093E\u0924\u093E\u0921\u094D\u092F \u0927\u093E\u0935\u0924\u093F\u0965<br> \u0924\u0925\u093E \u092C\u093F\u0928\u094D\u0926\u0941\u0930\u094D\u0935\u0930\u093E\u0930\u094B\u0939 \u0909\u091A\u094D\u091A\u093E\u0930\u0947\u0923\u0948\u0935 \u0927\u093E\u0935\u0924\u093F\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0905\u0928\u094D\u092F\u0924\u094D\u0930\u093E\u092A\u093F</p><blockquote><p>\u0924\u0926\u094D\u0917\u094D\u0930\u0939\u094B \u092E\u0928\u094D\u0924\u094D\u0930\u0938\u0926\u094D\u092D\u093E\u0935\u0903...\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0905\u0924\u094D\u0930 \u0939\u093F \u0924\u0926\u094D\u0935\u0926\u093F\u0924\u094D\u092F\u0915\u0943\u0924\u0915\u0928\u093F\u091C\u094B\u0926\u094D\u092F\u094B\u0917\u092C\u0932\u0947\u0928 \u092F\u094B\u0917\u0940\u0928\u094D\u0926\u094D\u0930\u094B \u092E\u0928\u0903 \u0915\u0930\u094D\u092E \u092C\u093F\u0928\u094D\u0926\u0941\u0902 \u0935\u093F\u0915\u0930\u094D\u0937\u092F\u0947\u0924\u094D\u092A\u0930\u092A\u094D\u0930\u0915\u093E\u0936\u093E\u0924\u094D\u092E\u0924\u093E\u0902 \u092A\u094D\u0930\u093E\u092A\u092F\u0947\u0926\u093F\u0924\u093F\u0964 \u0924\u0925\u093E \u092C\u093F\u0928\u094D\u0926\u0941\u0903 \u092A\u0930\u092A\u094D\u0930\u0915\u093E\u0936\u094B\u093D\u0915\u0943\u0924\u0915\u094B\u0926\u094D\u092F\u0928\u094D\u0924\u0943\u0924\u093E\u0924\u094D\u092E\u0928\u094B\u091A\u094D\u091A\u093E\u0930\u0947\u0923 \u0927\u093E\u0935\u0924\u093F \u092A\u094D\u0930\u0938\u0930\u0924\u0940\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u090F\u0924\u091A\u094D\u091A \u0938\u094D\u092A\u0928\u094D\u0926\u0947</p><blockquote><p>\u0905\u092F\u092E\u0947\u0935\u094B\u0926\u092F\u0938\u094D\u0924\u0938\u094D\u092F \u0927\u094D\u092F\u0947\u092F\u0938\u094D\u092F \u0927\u094D\u092F\u093E\u092F\u093F\u091A\u0947\u0924\u0938\u093F\u0964<br> \u0924\u0926\u093E\u0924\u094D\u092E\u0924\u093E\u0938\u092E\u093E\u092A\u0924\u094D\u0924\u093F\u0930\u093F\u091A\u094D\u091B\u0924\u0903 \u0938\u093E\u0927\u0915\u0938\u094D\u092F \u092F\u093E\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928\u094B\u0915\u094D\u0924\u092E\u094D\u0965\u0968\u0965</p></div><hr><div class="trans"><p>Asya ca\u2014</p><blockquote><p><strong>Prayatna\u1E25 s\u0101dhaka\u1E25||2||</strong></p></blockquote><p>Yathoktar\u016Bpasya mantrasy\u0101nusandhits\u0101prathamonme\u1E63\u0101va\u1E63\u1E6Dambhaprayatan\u0101tm\u0101 ak\u1E5Btako ya\u1E25 prayatna\u1E25 sa eva s\u0101dhako mantrayiturmantradevat\u0101t\u0101d\u0101tmyaprada\u1E25| Tadukta\u1E41 \u015Br\u012Btantrasadbh\u0101ve</p><blockquote><p>\u0100mi\u1E63a\u1E41 tu yath\u0101 khastha\u1E25 sampa\u015Bya\xF1\u015Bakuni\u1E25 priye|<br> K\u1E63ipram\u0101kar\u1E63ayedyadvadvegena sahajena tu||<br> Tadvadeva hi yog\u012Bndro mano bindu\u1E41 vikar\u1E63ayet|<br> Yath\u0101 \u015Baro dhanu\u1E25sa\u1E41stho yatnen\u0101t\u0101\u1E0Dya dh\u0101vati||<br> Tath\u0101 bindurvar\u0101roha ucc\u0101re\u1E47aiva dh\u0101vati||</p></blockquote><p>iti| Anyatr\u0101pi</p><blockquote><p>Tadgraho mantrasadbh\u0101va\u1E25...|</p></blockquote><p>iti| Atra hi tadvadityak\u1E5Btakanijodyogabalena yog\u012Bndro mana\u1E25 karma bindu\u1E41 vikar\u1E63ayetparaprak\u0101\u015B\u0101tmat\u0101\u1E41 pr\u0101payediti| Tath\u0101 bindu\u1E25 paraprak\u0101\u015Bo&#39;k\u1E5Btakodyant\u1E5Bt\u0101tmanocc\u0101re\u1E47a dh\u0101vati prasarat\u012Btyartha\u1E25| Etacca spande</p><blockquote><p>Ayamevodayastasya dhyeyasya dhy\u0101yicetasi|<br> Tad\u0101tmat\u0101sam\u0101pattiricchata\u1E25 s\u0101dhakasya y\u0101||</p></blockquote><p>ityanenoktam||2||</p></div><hr><p>\u0418 <em>(ca)</em> \u0438\u0437 \u044D\u0442\u043E\u0439 [\u043C\u0430\u043D\u0442\u0440\u044B] <em>(asya)</em>\u2014</p><blockquote><p><strong>[\u0423\u0441\u0435\u0440\u0434\u043D\u043E\u0435 \u0438 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0435] \u0443\u0441\u0438\u043B\u0438\u0435 <em>(prayatna\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u043C \u0434\u043B\u044F \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u0443\u0441\u043F\u0435\u0445\u0430 <em>(s\u0101dhaka\u1E25)</em>||2||</strong></p></blockquote><p>Prayatna <em>(prayatna\u1E25)</em> [\u2014 \u044D\u0442\u043E] \u0442\u043E <em>(ya\u1E25)</em> \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0435 <em>(ak\u1E5Btaka\u1E25)</em> \u0443\u0441\u0438\u043B\u0438\u0435 <em>(prayatana-\u0101tm\u0101)</em>, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u043D\u0430 \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u043C \u0443\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0438 <em>(ava\u1E63\u1E6Dambha)</em> \u043F\u0435\u0440\u0432\u043E\u0433\u043E <em>(prathama)</em> \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(unme\u1E63a)</em> \u0436\u0435\u043B\u0430\u043D\u0438\u044F \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u044C <em>(anusandhits\u0101)</em> \u043C\u0430\u043D\u0442\u0440\u0443 <em>(mantrasya)</em> , \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(r\u016Bpasya)</em> \u0431\u044B\u043B\u0430 \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u0430 \u0440\u0430\u043D\u0435\u0435 [\u0432 \u043F\u0435\u0440\u0432\u043E\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435] <em>(yath\u0101 ukta)</em><sup>1</sup>. [\u0418] \u044D\u0442\u043E\u0442 [prayatna] <em>(sa\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u043C \u0434\u043B\u044F \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u0443\u0441\u043F\u0435\u0445\u0430 <em>(s\u0101dhaka\u1E25)</em>, \u0442.\u0435. \u043E\u043D \u0434\u0430\u0440\u0443\u0435\u0442 <em>(prada\u1E25)</em> \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C <em>(t\u0101d\u0101tmya)</em> \u0441 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C <em>(devat\u0101)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra)</em> \u0442\u043E\u043C\u0443, \u043A\u0442\u043E \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 \u043D\u0430\u0434 \u043C\u0430\u043D\u0442\u0440\u043E\u0439 <em>(mantrayitu\u1E25)</em> --\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, prayatna \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 \u043E\u0441\u043E\u0437\u043D\u0430\u0442\u044C, \u0447\u0442\u043E \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C \u043C\u0430\u043D\u0442\u0440\u044B, \u0442.\u0435. \u0412\u044B\u0441\u0448\u0438\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C--|</p><p>\u042D\u0442\u0430 \u0436\u0435 [\u0441\u0430\u043C\u0430\u044F \u0438\u0441\u0442\u0438\u043D\u0430] <em>(tad)</em> \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0430\u0435\u0442\u0441\u044F <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Tantrasadbh\u0101va <em>(\u015Br\u012B-tantrasadbh\u0101ve)</em>:</p><blockquote><p>&quot;\u041E \u0434\u043E\u0440\u043E\u0433\u0430\u044F <em>(priye)</em>!, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A <em>(yath\u0101... yad-vat)</em> \u043F\u0442\u0438\u0446\u0430 <em>(\u015Bakuni\u1E25)</em> \u0432 \u043D\u0435\u0431\u0435 <em>(kha-stha\u1E25)</em>, \u0443\u0432\u0438\u0434\u0435\u0432 <em>(sampa\u015Byan)</em> \u043C\u044F\u0441\u043E <em>(\u0101mi\u1E63am)</em> [\u043D\u0430 \u0437\u0435\u043C\u043B\u0435], \u0442\u0430\u0449\u0438\u0442 [\u0435\u0433\u043E] \u043A \u0441\u0435\u0431\u0435 <em>(\u0101kar\u1E63ayet)</em> \u0431\u044B\u0441\u0442\u0440\u043E <em>(k\u1E63ipram)</em> \u0441 \u043F\u0440\u0438\u0440\u043E\u0434\u043D\u043E\u0439 \u043B\u043E\u0432\u043A\u043E\u0441\u0442\u044C\u044E \u0438 \u0441\u0442\u0440\u0435\u043C\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E <em>(vegena sahajena)</em> \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 <em>(tu... tu)</em>, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 <em>(tad-vat)</em>, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F <em>(eva hi)</em>, \u0433\u043B\u0430\u0432\u043D\u044B\u0439 <em>(indra\u1E25)</em> \u0441\u0440\u0435\u0434\u0438 Yog\u012B-s <em>(yogi)</em> \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 <em>(vikar\u1E63ayet)</em> [\u0441\u0432\u043E\u0439] \u0443\u043C <em>(manas)</em> \u043A Bindu <em>(bindum)</em><sup>2</sup>. \u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A <em>(yath\u0101)</em> \u0441\u0442\u0440\u0435\u043B\u0430 <em>(\u015Bara\u1E25)</em>, \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u043D\u0430\u044F \u0432 <em>(sa\u1E41stha\u1E25)</em> \u043B\u0443\u043A <em>(dhanus)</em>, \u0443\u0441\u0442\u0440\u0435\u043C\u043B\u044F\u0435\u0442\u0441\u044F [\u043A \u0441\u0432\u043E\u0435\u0439 \u0446\u0435\u043B\u0438] <em>(dh\u0101vati)</em> \u043F\u043E\u0441\u043B\u0435 \u043D\u0430\u0442\u044F\u0436\u0435\u043D\u0438\u044F [\u043B\u0443\u043A\u0430] <em>(\u0101t\u0101\u1E0Dya)</em> \u0441 \u0443\u0441\u0438\u043B\u0438\u0435\u043C <em>(yatnena)</em>, \u0442\u0430\u043A\u0436\u0435 \u0438 <em>(tath\u0101)</em>, \u041E \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u0430\u044F <em>(vara-\u0101rohe)</em>!, Bindu <em>(bindu\u1E25)</em> \u0443\u0441\u0442\u0440\u0435\u043C\u043B\u044F\u0435\u0442\u0441\u044F --\u0442.\u0435. \u0442\u0435\u0447\u0435\u0442, \u043F\u0440\u043E\u0434\u0432\u0438\u0433\u0430\u0435\u0442\u0441\u044F, \u0440\u0430\u0441\u0448\u0438\u0440\u044F\u0435\u0442\u0441\u044F-- <em>(dh\u0101vati)</em> \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E ucc\u0101ra --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u0443\u043C\u0430 \u0432\u0432\u0435\u0440\u0445, \u0442.\u0435. \u043A Bindu-- <em>(ucc\u0101re\u1E47a eva... iti)</em>&quot;||</p></blockquote><p>\u0412 \u0434\u0440\u0443\u0433\u043E\u043C \u043C\u0435\u0441\u0442\u0435 <em>(anyatra)</em> [\u044D\u0442\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0431\u044B\u043B\u043E \u043A\u043E\u043D\u0441\u0442\u0430\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043E] <em>(api)</em>:</p><blockquote><p>&quot;\u041F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 --\u0438\u043B\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435-- <em>(graha\u1E25)</em> \u042D\u0442\u043E\u0433\u043E --\u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430-- <em>(tad)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439 <em>(sat)</em> \u0441\u0443\u0442\u044C\u044E --\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E-- <em>(bh\u0101va\u1E25)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra... iti)</em>...&quot;|</p></blockquote><p>\u0417\u0434\u0435\u0441\u044C --\u0442.\u0435. \u0432 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 \u0441\u0442\u0438\u0445\u0430\u0445 Tantrasadbh\u0101va-- <em>(atra hi)</em> [\u0442\u0435\u0440\u043C\u0438\u043D] &quot;tadvat&quot; --\u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435-- <em>(tad-vat iti)</em> [\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442], \u0447\u0442\u043E \u0433\u043B\u0430\u0432\u043D\u044B\u0439 <em>(indra\u1E25)</em> \u0441\u0440\u0435\u0434\u0438 Yog\u012B-s <em>(yogi)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(balena)</em> \u0441\u0432\u043E\u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(nija)</em> \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0433\u043E <em>(ak\u1E5Btaka)</em> \u0443\u0441\u0438\u043B\u0438\u044F <em>(udyoga)</em>, \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 <em>(vikar\u1E63ayet)</em> \u0443\u043C <em>(manas)</em>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0434\u043E\u043B\u0436\u0435\u043D \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C\u0441\u044F \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u043A\u0430\u043A] \u043A\u0430\u0440\u043C\u0430, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442 [\u0432 \u0434\u0430\u043D\u043D\u043E\u043C \u0442\u043E\u043B\u043A\u043E\u0432\u0430\u043D\u0438\u0438] <em>(karma)</em><sup>3</sup>, \u043A Bindu <em>(bindum)</em>. [\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438,] &quot;\u043E\u043D \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 [\u0441\u0432\u043E\u0439 \u0443\u043C] \u0434\u043E\u0441\u0442\u0438\u0447\u044C <em>(pr\u0101payet)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(para)</em> \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(prak\u0101\u015Ba-\u0101tmat\u0101m... iti)</em>&quot;|</p><p>&quot;\u0422\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em>, Bindu <em>(bindu\u1E25)</em>, \u0412\u0441\u0435\u0432\u044B\u0448\u043D\u0438\u0439 <em>(para)</em> \u0421\u0432\u0435\u0442 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(prak\u0101\u015Ba\u1E25)</em>, \u0443\u0441\u0442\u0440\u0435\u043C\u043B\u044F\u0435\u0442\u0441\u044F <em>(dh\u0101vati)</em>, \u0442.\u0435. \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F, \u0440\u0430\u0441\u0448\u0438\u0440\u044F\u0435\u0442\u0441\u044F <em>(prasarati)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C ucc\u0101ra <em>(ucc\u0101re\u1E47a)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(\u0101tman\u0101)</em> \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u044B\u043C <em>(ak\u1E5Btaka)</em> \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u0435\u043C <em>(udyant\u1E5Bt\u0101)</em> [\u0443\u043C\u0430]&quot;. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(iti artha\u1E25)</em>|</p><p>\u042D\u0442\u043E <em>(etad ca)</em> \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E <em>(uktam)</em> \u0432 Spandak\u0101rik\u0101-s <em>(spande)</em> \u0432 \u044D\u0442\u043E\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435] <em>(anena)</em>:</p><blockquote><p>&quot;\u0422\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u044D\u0442\u043E <em>(ayam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C <em>(udaya\u1E25)</em> \u044D\u0442\u043E\u0433\u043E <em>(tasya)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u0430 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438 <em>(dhyeyasya)</em> \u0432 \u0443\u043C\u0435 <em>(cetasi)</em> \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u0443\u044E\u0449\u0435\u0433\u043E <em>(dhy\u0101yi)</em>. [\u041A\u043E\u0440\u043E\u0447\u0435,] \u0434\u043B\u044F s\u0101dhaka, \u0438\u043B\u0438 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u043F\u043E\u0434\u0432\u0438\u0436\u043D\u0438\u043A\u0430 <em>(s\u0101dhakasya)</em> \u0441 \u0442\u0432\u0435\u0440\u0434\u043E\u0439 \u0432\u043E\u043B\u0435\u0439 <em>(icchata\u1E25)</em> \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sam\u0101patti\u1E25... y\u0101)</em> [\u0435\u0433\u043E] \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u0438 [\u0441 dhyeya, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438] <em>(tad\u0101tmat\u0101... iti)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s II, 6]</p></blockquote><p>||2||</p><hr><ol><li><p>Prayatna \u2014 \u044D\u0442\u043E \u0443\u0441\u0435\u0440\u0434\u043D\u043E\u0435 \u0438 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0435 \u0443\u0441\u0438\u043B\u0438\u0435, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u043D\u0430 \u043F\u0440\u043E\u0447\u043D\u043E\u043C \u0443\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u043D\u0438\u0438 \u043F\u0435\u0440\u0432\u043E\u0433\u043E \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0443\u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u044F \u043A \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044E \u043C\u0430\u043D\u0442\u0440\u044B. \u041A\u043E\u0433\u0434\u0430 \u044D\u0442\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u0435 \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u043F\u0435\u0440\u0432\u044B\u0435 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u044F \u043C\u0430\u043D\u0442\u0440\u044B, \u0442\u043E \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0435 \u0438 \u0442\u0432\u0435\u0440\u0434\u043E\u0435 \u0443\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 \u0435\u0433\u043E \u0438 \u0435\u0441\u0442\u044C prayatna.</p></li><li><p>\u0412 \u0422\u0440\u0438\u043A\u0435 \u0442\u0435\u0440\u043C\u0438\u043D &quot;bindu&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0442\u0430\u043A \u043C\u043D\u043E\u0433\u043E \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0432\u0435\u0449\u0435\u0439, \u0447\u0442\u043E \u0437\u0430\u0434\u0430\u0447\u0430 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u0445 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043D\u0435 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u043C\u0430 \u0434\u043B\u044F \u043F\u0440\u043E\u0441\u0442\u043E\u0433\u043E \u043F\u043E\u044F\u0441\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u044F. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, \u043E\u043D \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0431\u0435\u0437\u0440\u0430\u0437\u0434\u0435\u043B\u044C\u043D\u044B\u0439 \u0421\u0432\u0435\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0442.\u0435. \u0421\u0432\u0435\u0442 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F.</p></li><li><p>&quot;Karma&quot; \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0437\u0434\u0435\u0441\u044C \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0442\u0435\u0440\u043C\u0438\u043D\u0430 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0439 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u043A\u0438. \u041E\u043D \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043E\u0431\u044A\u0435\u043A\u0442, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0439 \u0441 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u043C\u044B\u043C \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C, \u0438\u043B\u0438 &quot;kart\u1E5B&quot;. \u0412 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u044F \u0430\u043A\u0442\u0438\u0432\u043D\u0430, \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u0441\u043B\u043E\u0432\u043E &quot;manas&quot; (\u0443\u043C) \u0443\u043F\u043E\u0442\u0440\u0435\u0431\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0412\u0438\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435. \u0421 \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u0435\u0441\u043B\u0438 \u0431\u044B \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u044F \u0431\u044B\u043B\u0430 \u043F\u0430\u0441\u0441\u0438\u0432\u043D\u0430, \u0442\u0435\u0440\u043C\u0438\u043D &quot;manas&quot; \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043B\u043E \u0431\u044B \u0443\u043F\u043E\u0442\u0440\u0435\u0431\u0438\u0442\u044C \u0432 \u0418\u043C\u0435\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435. \u0412\u044B \u043C\u043E\u0433\u043B\u0438 \u0431\u044B \u0441\u043A\u0430\u0437\u0430\u0442\u044C: &quot;O, \u0413\u043E\u0441\u043F\u043E\u0434\u0438, \u043A\u0430\u043A \u0441\u043B\u043E\u0436\u043D\u043E!&quot;, \u0438 \u0431\u044B\u043B\u0438 \u0431\u044B \u043F\u0440\u0430\u0432\u044B, \u0445\u0435\u0445\u0435, \u0442\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 \u044F \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u044E \u0432\u0430\u043C \u0437\u0434\u0435\u0441\u044C \u043F\u0440\u043E\u0441\u0442\u043E\u0439 \u043F\u0440\u0438\u043C\u0435\u0440: &quot;\u041E\u043D \u0434\u0432\u0438\u0436\u0435\u0442 \u0443\u043C&quot; - \u0430\u043A\u0442\u0438\u0432\u043D\u0430\u044F \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u044F; \u0433\u0434\u0435 &quot;\u0443\u043C&quot;\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F &quot;\u0434\u0432\u0438\u0433\u0430\u0442\u044C&quot;, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F, \u043A\u0430\u043A &quot;\u043E\u043D&quot; \u2014 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C. \u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435, &quot;\u0443\u043C&quot; \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043A\u043B\u043E\u043D\u044F\u0442\u044C \u0432 \u0412\u0438\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435. &quot;\u0423\u043C \u0434\u0432\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0438\u043C&quot; - \u043F\u0430\u0441\u0441\u0438\u0432\u043D\u0430\u044F \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u044F; &quot;\u0443\u043C&quot; \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u0431\u044B\u0442\u044C \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u043D\u043E \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435, \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u043A\u043B\u043E\u043D\u044F\u0442\u044C\u0441\u044F \u0432 \u0438\u043C\u0435\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0442\u0435\u0440\u043C\u0438\u043D &quot;manas&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0440\u043E\u0434\u0430, \u0441 \u043E\u043A\u043E\u043D\u0447\u0430\u043D\u0438\u0435\u043C &quot;as&quot;, \u0442\u043E \u0438 \u0418\u043C\u0435\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439, \u0438 \u0412\u0438\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0430\u0434\u0435\u0436\u0438 \u0441\u043E\u0432\u043F\u0430\u0434\u0430\u044E\u0442 \u0434\u0440\u0443\u0433 \u0441 \u0434\u0440\u0443\u0433\u043E\u043C \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0447\u0438\u0441\u043B\u0435 (\u0432 \u0434\u0432\u043E\u0439\u043D\u043E\u043C \u0438 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0442\u0430\u043A\u0436\u0435, \u043D\u043E \u0441\u043B\u043E\u0432\u043E \u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u043D\u0430 &quot;manas\u012B&quot; \u0438 &quot;man\u0101\u1E41si&quot;, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E), \u0442.\u0435.\u0432 \u043E\u0431\u043E\u0438\u0445 \u0441\u043B\u0443\u0447\u0430\u044F\u0445 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u043E\u0434\u043D\u043E \u0438 \u0442\u043E \u0436\u0435 \u0441\u043B\u043E\u0432\u043E \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0447\u0438\u0441\u043B\u0435 \u2014&quot;manas&quot;. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0432\u044B \u043D\u0435 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0442\u0435 \u0440\u0430\u0437\u043D\u0438\u0446\u0443, \u0435\u0441\u043B\u0438 \u0432\u044B \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0445\u043E\u0440\u043E\u0448\u043E \u0432\u043B\u0430\u0434\u0435\u0435\u0442\u0435 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0439 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u043A\u043E\u0439. \u041E\u0434\u043D\u0430\u043A\u043E, \u0441 \u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C\u0438, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, &quot;yoga&quot;, \u0432\u044B \u043E\u0447\u0435\u043D\u044C \u043B\u0435\u0433\u043A\u043E \u0437\u0430\u043C\u0435\u0442\u0438\u0442\u0435 \u0440\u0430\u0437\u043D\u0438\u0446\u0443, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0418\u043C\u0435\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u0438 \u0412\u0438\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0430\u0434\u0435\u0436\u0438 \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0447\u0438\u0441\u043B\u0435 \u043E\u0442\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F: &quot;yoga\u1E25&quot; (\u0418\u043C\u0435\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439) \u0438 &quot;yogam&quot; (\u0412\u0438\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439).</p></li></ol></div>',1),u=[r];function p(n,i,s,d,y,q){return t(),e("div",null,u)}var c=a(o,[["render",p]]);export{k as __pageData,c as default};
